/**
 * Resolve the scheduler module's environment-driven config (SPEC §13).
 *
 * Env contract:
 *   WARREN_SCHEDULER_TICK_MS   tick interval in ms — default 60_000 (one minute)
 *   WARREN_SCHEDULER_DISABLED  disable the scheduler entirely — accepts the
 *                              standard warren truthy set ("1"/"true"/"yes"/"on")
 *   WARREN_SD_BINARY           seeds CLI binary path — default "sd"
 *
 * One minute is the natural floor for cron grammar (5-token expressions
 * resolve to minute-level slots); ticking faster wastes work, ticking
 * slower means cron slots can be missed if a tick straddles them.
 * Acceptance + tests inject smaller intervals via the API directly rather
 * than the env var so production never accidentally subminute-ticks.
 */

import { ValidationError } from "../core/errors.ts";

export const DEFAULT_SCHEDULER_TICK_MS = 60_000;
export const DEFAULT_SD_BINARY = "sd";

export interface TriggerSchedulerConfig {
	readonly tickMs: number;
	readonly disabled: boolean;
	readonly sdBinary: string;
}

export type EnvLike = Readonly<Record<string, string | undefined>>;

export function loadTriggerSchedulerConfigFromEnv(
	env: EnvLike = process.env,
): TriggerSchedulerConfig {
	const tickMs = parseTickMs(env.WARREN_SCHEDULER_TICK_MS);
	const disabled = parseBoolFlag(env.WARREN_SCHEDULER_DISABLED);
	const sdBinary = env.WARREN_SD_BINARY ?? DEFAULT_SD_BINARY;

	if (sdBinary === "") {
		throw new ValidationError("WARREN_SD_BINARY is set to an empty string", {
			recoveryHint: `unset WARREN_SD_BINARY to fall back to "${DEFAULT_SD_BINARY}"`,
		});
	}

	return { tickMs, disabled, sdBinary };
}

function parseTickMs(raw: string | undefined): number {
	if (raw === undefined || raw === "") return DEFAULT_SCHEDULER_TICK_MS;
	const parsed = Number(raw);
	if (!Number.isFinite(parsed) || parsed <= 0) {
		throw new ValidationError(`WARREN_SCHEDULER_TICK_MS must be a positive integer, got "${raw}"`, {
			recoveryHint: `unset or set to a positive integer (default ${DEFAULT_SCHEDULER_TICK_MS})`,
		});
	}
	return Math.trunc(parsed);
}

// Default-OFF opt-in flag: use the canonical allow-list truthy set from
// PR #340 ("1"/"true"/"yes"/"on", case-insensitive) so out-of-set garbage
// resolves to false (fail-safe) and matches the documented env contract.
// (Unlike the default-ON WARREN_AUTO_OPEN_PR, which correctly uses a
// deny-list opt-out posture.)
function parseBoolFlag(raw: string | undefined): boolean {
	if (raw === undefined) return false;
	const t = raw.trim().toLowerCase();
	return t === "1" || t === "true" || t === "yes" || t === "on";
}

/**
 * Per-trigger dispatch decisions for the R-06 scheduler.
 *
 * Two flows live here:
 *
 *   `dispatchCronTrigger` walks one cron entry against the warren-side
 *      triggers row to decide fire vs skip. The "no catch-up" semantic
 *      (pl-2f15 alternatives #4 / open-question #4) is encoded as:
 *
 *        first observation   → seed the row at `now`, do NOT fire
 *        previousRun > last  → fire ONCE, advance to `nextRun(now)`
 *        otherwise           → no fire; refresh `nextFireAt` only
 *
 *      This skips every missed slot during downtime: a 4-hour outage on
 *      an hourly trigger dispatches at most one run when warren comes
 *      back, not four.
 *
 *   `dispatchScheduledSeed` fires for any open seed whose
 *      `extensions.scheduledFor` is <= now. Order of operations matches
 *      pl-2f15 risk #4: spawn the run first, surface the (warren) run
 *      id as `trigger='scheduled'`, then call `clearScheduledFor`. The
 *      caller (tick loop) records system events on dispatch failure so
 *      the operator sees lingering scheduledFor extensions on the run.
 *
 * Both flows return a discriminated result the tick loop logs and
 * persists; neither throws on per-trigger failure so one bad entry can't
 * tear down the scheduler.
 */

import type { Repos } from "../db/repos/index.ts";
import type { ScheduledSeed } from "../seeds-cli/index.ts";
import type { CronTrigger, DefaultsConfig } from "../warren-config/index.ts";
import { parseCron } from "./cron.ts";
import { TriggerDispatchError } from "./errors.ts";

export interface DispatchSpawnInput {
	readonly agentName: string;
	readonly projectId: string;
	readonly prompt: string;
	readonly trigger: string;
	readonly metadata?: unknown;
}

export interface DispatchSpawnResult {
	readonly runId: string;
}

/**
 * Minimal seam the dispatcher needs from the runs spawn pipeline. The
 * production wiring (tick.ts) plugs `spawnRun` here with all the
 * burrow/project context baked in via closure; tests inject a stub that
 * just returns a synthetic runId.
 */
export type DispatchSpawnFn = (input: DispatchSpawnInput) => Promise<DispatchSpawnResult>;

export interface DispatchCronInput {
	readonly projectId: string;
	readonly trigger: CronTrigger;
	readonly defaults?: DefaultsConfig | null;
	readonly now: Date;
	readonly repos: Pick<Repos, "triggers">;
	readonly spawn: DispatchSpawnFn;
}

export type DispatchCronResult =
	| {
			readonly kind: "fired";
			readonly runId: string;
			readonly firedAt: Date;
			readonly nextFireAt: Date | null;
	  }
	| {
			readonly kind: "seeded";
			readonly nextFireAt: Date | null;
	  }
	| {
			readonly kind: "skipped";
			readonly nextFireAt: Date | null;
			readonly reason: string;
	  }
	| {
			readonly kind: "error";
			readonly reason: string;
	  };

export async function dispatchCronTrigger(input: DispatchCronInput): Promise<DispatchCronResult> {
	const parseInput: { expression: string; timezone?: string } = {
		expression: input.trigger.cron,
		...(input.trigger.timezone !== undefined ? { timezone: input.trigger.timezone } : {}),
	};
	const parsed = parseCron(parseInput);
	if (!parsed.ok) {
		return { kind: "error", reason: `cron parse failed: ${parsed.message}` };
	}

	const row = await input.repos.triggers.get({
		projectId: input.projectId,
		triggerId: input.trigger.id,
	});
	const nextFireAt = parsed.cron.nextRun(input.now);

	if (row === null || row.lastFiredAt === null) {
		// First observation — seed the row at `now` so the prev/last
		// comparison on the next tick can detect a genuine new slot.
		await input.repos.triggers.upsert({
			projectId: input.projectId,
			triggerId: input.trigger.id,
			lastFiredAt: input.now.toISOString(),
			nextFireAt: nextFireAt?.toISOString() ?? null,
		});
		return { kind: "seeded", nextFireAt };
	}

	const last = new Date(row.lastFiredAt);
	const prev = parsed.cron.previousRun(input.now);
	if (prev === null || prev <= last) {
		// No new slot has elapsed since the last fire — refresh nextFireAt
		// in case the trigger expression changed and we need to roll the
		// upcoming-fire indicator forward.
		await input.repos.triggers.upsert({
			projectId: input.projectId,
			triggerId: input.trigger.id,
			nextFireAt: nextFireAt?.toISOString() ?? null,
		});
		return {
			kind: "skipped",
			nextFireAt,
			reason: "no new cron slot since last fire",
		};
	}

	const prompt = resolveCronPrompt(input.trigger, input.defaults);
	let runId: string;
	try {
		const spawned = await input.spawn({
			agentName: input.trigger.role,
			projectId: input.projectId,
			prompt,
			trigger: "cron",
			metadata: {
				triggerId: input.trigger.id,
				cron: input.trigger.cron,
				...(input.trigger.seed !== undefined ? { seed: input.trigger.seed } : {}),
			},
		});
		runId = spawned.runId;
	} catch (err) {
		// Per pl-2f15 risk #5 we keep dispatch failures per-trigger; surface
		// the reason for the tick log without touching the row. Next tick
		// will recompute prev > last and retry.

	.object({
		type: z.literal("static"),
		mode: PreviewModeSchema.optional(),
	})
	.passthrough();

export const PreviewConfigSchema = z.discriminatedUnion("type", [
	ServerPreviewConfigSchema,
	StaticPreviewConfigSchema,
]);

export type ServerPreviewConfig = z.infer<typeof ServerPreviewConfigSchema>;
export type StaticPreviewConfig = z.infer<typeof StaticPreviewConfigSchema>;
export type PreviewConfig = z.infer<typeof PreviewConfigSchema>;

const CronTriggerSchema = z
	.object({
		id: TriggerIdSchema,
		kind: z.literal("cron"),
		cron: CronExpressionSchema,
		seed: SeedRefSchema.optional(),
		role: RoleNameSchema,
		timezone: TimezoneSchema.optional(),
		prompt: PromptSchema.optional(),
	})
	.strict();

export const TriggerSchema = z.discriminatedUnion("kind", [CronTriggerSchema]);

export const TriggersConfigSchema = z.array(TriggerSchema).superRefine((list, ctx) => {
	const seen = new Set<string>();
	list.forEach((entry, index) => {
		if (seen.has(entry.id)) {
			ctx.addIssue({
				code: "custom",
				path: [index, "id"],
				message: `duplicate trigger id "${entry.id}"`,
			});
		}
		seen.add(entry.id);
	});
});

export type CronTrigger = z.infer<typeof CronTriggerSchema>;
export type Trigger = z.infer<typeof TriggerSchema>;
export type TriggersConfig = z.infer<typeof TriggersConfigSchema>;

export const DefaultsConfigSchema = z
	.object({
		defaultRole: RoleNameSchema.optional(),
		defaultBranch: z.string().min(1, "defaultBranch must be non-empty if provided").optional(),
		defaultPrompt: PromptSchema.optional(),
		// warren-618b: free-text provider/model defaults applied at spawn time the
		// same way per-run overrides are (operator > project default > frontmatter).
		defaultProvider: z.string().min(1, "defaultProvider must be non-empty if provided").optional(),
		defaultModel: z.string().min(1, "defaultModel must be non-empty if provided").optional(),
		// warren-9993: run branch prefix; spawnRun composes `${prefix}/${run.id}`.
		// Precedence: project default > WARREN_RUN_BRANCH_PREFIX env > "burrow".
		runBranchPrefix: RunBranchPrefixSchema.optional(),
		// warren-7be9 / SPEC §11.L: per-run preview environments (R-19). Canonical

