/**
 * Schemas for canopy `cn render` output and warren's normalized agent
 * definition (SPEC §4.2).
 *
 * `RenderResponseSchema` mirrors the wire shape canopy 0.2.x emits with
 * `--format json` — `{success, command, name, version, sections, ...}`.
 * Failure-shaped responses (`success: false`) are caught at the canopy
 * facade boundary, so the schema only needs to model the happy-path
 * envelope.
 *
 * `parseRenderedAgent` collapses the section list into a `name → body`
 * map (the rest of warren never cares about ordering — `cn render` already
 * resolved inheritance + mixins). It also enforces warren's semantic rule:
 * an agent prompt MUST include a `system` section. Other sections from
 * SPEC §4.2 (`skills`, `expertise_seed`, `burrow_config`, `workflow`) are
 * optional — they are consumed at run-spawn time (Phase 5), not now, and
 * canopy's own per-prompt schema is the right place to enforce richer
 * structural rules.
 *
 * Duplicate section names are rejected: canopy renders an inherited
 * prompt by overriding parent sections with same-named child sections, so
 * the rendered output should never contain dupes. If we see one, the
 * canopy install is corrupt — surface that loudly rather than silently
 * dropping data.
 */

import { z } from "zod";
import { AgentSchemaError } from "./errors.ts";

export const REQUIRED_AGENT_SECTIONS = ["system"] as const;
export type RequiredAgentSection = (typeof REQUIRED_AGENT_SECTIONS)[number];

const SectionSchema = z.object({
	name: z.string().min(1),
	body: z.string(),
});

export const RenderResponseSchema = z.object({
	success: z.literal(true),
	command: z.literal("render"),
	name: z.string().min(1),
	version: z.number().int().positive(),
	sections: z.array(SectionSchema),
	resolvedFrom: z.array(z.string()).optional(),
	frontmatter: z.record(z.string(), z.unknown()).optional(),
});

export type RenderResponse = z.infer<typeof RenderResponseSchema>;

export interface AgentDefinition {
	readonly name: string;
	readonly version: number;
	readonly sections: Readonly<Record<string, string>>;
	readonly resolvedFrom: readonly string[];
	readonly frontmatter: Readonly<Record<string, unknown>>;
}

/**
 * Well-known optional frontmatter fields the multi-provider surface reads:
 *
 *   provider — the runtime-side provider id (e.g. "anthropic", "openai",
 *              "google", "deepseek"). Free-form string; burrow's piRuntime
 *              maps it onto pi's --provider flag, claude-code ignores it.
 *   model    — provider-specific model id (e.g. "claude-sonnet-4-6",
 *              "gpt-4o", "gemini-2.0-pro"). Free-form string; the runtime
 *              decides how to interpret it.
 *   runtime  — burrow runtime id this canopy agent dispatches onto
 *              (e.g. "claude-code", "sapling", "pi"). When unset,
 *              warren falls back to `DEFAULT_RUNTIME_ID` ("pi") —
 *              the multi-provider runtime is the preferred default
 *              (warren-16f8). claude-code stays available but is now
 *              opt-in: pin it via this field. Built-in agents that
 *              want a non-pi runtime (claude-code / sapling) declare
 *              it here explicitly; interactive system-prompt-only
 *              agents like `brainstorm` / `planner` (warren-ebca) do
 *              the same so they compose onto a real burrow runtime.
 *   auto_plan_run — boolean (warren-a32a). When true and the agent's run
 *              succeeds, reap diffs `.seeds/plans.jsonl` to detect new
 *              plans created during execution and auto-dispatches a
 *              plan-run for each. Enables the patrol agent pattern:
 *              cron fires a scan agent, the agent files a plan, warren
 *              auto-executes it.
 *   auto_plan_run_agent — string (warren-65b2). When set, the auto-
 *              dispatched plan-run uses this agent name instead of
 *              inheriting the parent run's agent name. Prevents
 *              triage-only agents (bugwatch, nightwatch) from
 *              propagating their system prompt to child runs that
 *              need to write code. Falls back to the parent run's
 *              agentName when unset.
 *
 * Both stay in the open `frontmatter` bag (no schema rev) so a canopy
 * author can set them inline. `POST /runs` accepts the same two fields
 * as overrides; the spawn composer merges overrides on top of frontmatter
 * before freezing onto `runs.rendered_agent_json`.
 */
export function readProviderFrontmatter(frontmatter: Readonly<Record<string, unknown>>): {
	provider?: string;
	model?: string;
} {
	const result: { provider?: string; model?: string } = {};
	const p = frontmatter.provider;
	if (typeof p === "string" && p.length > 0) result.provider = p;
	const m = frontmatter.model;
	if (typeof m === "string" && m.length > 0) result.model = m;
	return result;
}

/**
 * Default burrow runtime id warren dispatches onto when an agent pins
 * none (warren-16f8). Pi is the multi-provider runtime — cost streams
 * in-band, the unified provider matrix works, and it's what most
 * dogfood runs use — so it's the preferred default; claude-code is
 * opt-in via `frontmatter.runtime`.
 */
export const DEFAULT_RUNTIME_ID = "pi";

/**
 * Resolve the burrow runtime id this canopy agent should dispatch onto.
 *
 * Precedence (warren-b802 / warren-16f8):
 *   1. `configOverride` — per-project `.warren/config.yaml`
 *      `interactiveAgents.brainstormRuntime` / `plannerRuntime`
 *   2. `frontmatter.runtime` — declared by built-ins that pin a
 *      specific runtime (claude-code / sapling) or compose a system
 *      prompt onto an existing runtime (brainstorm / planner,
 *      warren-ebca)
 *   3. `DEFAULT_RUNTIME_ID` ("pi") — the preferred default when
 *      nothing pins a runtime; claude-code is opt-in
 */
export function readRuntimeId(agent: AgentDefinition, configOverride?: string): string {
	if (typeof configOverride === "string" && configOverride.length > 0) return configOverride;
	const r = agent.frontmatter.runtime;
	if (typeof r === "string" && r.length > 0) return r;
	return DEFAULT_RUNTIME_ID;
}

/**
 * Return a new AgentDefinition with the operator's provider/model overrides
 * folded into `frontmatter` (taking precedence over the agent's own values).
 * Empty / whitespace-only overrides are ignored — they're treated the same
 * as omitting the field. The original agent is not mutated.
 */
export function withProviderOverrides(
	agent: AgentDefinition,
	overrides: { providerOverride?: string; modelOverride?: string },
): AgentDefinition {
	const provider = overrides.providerOverride?.trim();
	const model = overrides.modelOverride?.trim();
	if ((provider === undefined || provider === "") && (model === undefined || model === "")) {
		return agent;
	}
	const nextFrontmatter: Record<string, unknown> = { ...agent.frontmatter };
	if (provider !== undefined && provider !== "") nextFrontmatter.provider = provider;
	if (model !== undefined && model !== "") nextFrontmatter.model = model;
	return { ...agent, frontmatter: nextFrontmatter };
}

/**
 * Parse and semantically validate the JSON body returned by
 * `cn render <name> --format json`. Throws `AgentSchemaError` for
 * any malformed or incomplete shape.
 */
export function parseRenderedAgent(raw: unknown, agentName?: string): AgentDefinition {
	const parsed = RenderResponseSchema.safeParse(raw);
	if (!parsed.success) {
		throw new AgentSchemaError(
			`canopy render output failed schema validation${agentName ? ` for "${agentName}"` : ""}: ${parsed.error.issues.map(formatZodIssue).join("; ")}`,
		);
	}
	const env = parsed.data;
	const sections: Record<string, string> = {};
	for (const section of env.sections) {
		if (Object.hasOwn(sections, section.name)) {
			throw new AgentSchemaError(
				`canopy render returned duplicate section "${section.name}" for agent "${env.name}"`,
			);
		}
		sections[section.name] = section.body;
	}
	const def: AgentDefinition = {
		name: env.name,
		version: env.version,
		sections,
		resolvedFrom: env.resolvedFrom ?? [],
		frontmatter: env.frontmatter ?? {},
	};
	validateAgentDefinition(def);
	return def;
}

/**
 * Enforce warren's required-sections rule on an already-built
 * `AgentDefinition`. Reused by `parseRenderedAgent` (post-canopy-render)
 * and by the cross-tier composer (warren-44a3) so a composed agent that
 * still ends up missing `system` is skipped with the same error shape.
 */
export function validateAgentDefinition(def: AgentDefinition): void {
	for (const required of REQUIRED_AGENT_SECTIONS) {
		if (!Object.hasOwn(def.sections, required)) {
			throw new AgentSchemaError(`agent "${def.name}" is missing required section "${required}"`, {
				recoveryHint: `add a "${required}" section to the canopy prompt and re-render`,
			});
		}
	}
}

/**
 * Read `auto_plan_run_agent` from agent frontmatter (warren-65b2).
 * Returns the override agent name, or `undefined` when unset.
 */
export function readAutoPlanRunAgent(
	frontmatter: Readonly<Record<string, unknown>>,
): string | undefined {
	const v = frontmatter.auto_plan_run_agent;
	if (typeof v === "string" && v.length > 0) return v;
	return undefined;
}

function formatZodIssue(issue: z.core.$ZodIssue): string {
	const path = issue.path.length === 0 ? "<root>" : issue.path.join(".");
	return `${path}: ${issue.message}`;
}

/**
 * Read-time cost/token hydration for runs whose bridge died before its
 * next checkpoint (warren-ab18).
 *
 * The bridge (`stream.ts`) accumulates session usage in-memory and
 * checkpoints it onto `runs.cost_usd` / `runs.tokens_*` periodically
 * (pi: on every agent-end envelope; claude-code: on the terminal
 * `result` envelope). If warren stalls or the host reboots before the
 * next checkpoint lands, those columns stay null even though the
 * underlying usage envelopes were already persisted to `events`.
 *
 * `hydrateRunsUsage` patches that gap at read time: for any terminal
 * run whose `costUsd` is still null, it sums the run's usage events
 * via `aggregateUsageFromEvents` and overlays the derived totals onto
 * the row before the handler serializes it. Non-terminal rows are left
 * untouched — the bridge is the source of truth while it's alive.
 *
 * This is a transitional fallback only: a real fix would also backfill
 * the columns on terminal reconciliation so subsequent reads don't pay
 * the aggregation cost. The seed (warren-ab18) explicitly defers that
 * backfill — keep this helper focused on the symptom (operator sees
 * `-` for cost) and let the next iteration close the gap.
 */

import type { EventsRepo } from "../db/repos/events.ts";
import type { RunRow, RunState } from "../db/schema.ts";
import { aggregateUsageFromEvents, eventRowToUsageInput } from "./usage-aggregate.ts";

const TERMINAL_RUN_STATES: ReadonlySet<RunState> = new Set(["succeeded", "failed", "cancelled"]);

/**
 * Subset of `EventsRepo` used for hydration. Declared structurally so
 * tests can stub the events fetch without instantiating a full repo.
 */
export interface UsageEventsFetcher {
	listUsageEvents(
		runIds: readonly string[],
	): Promise<
		readonly { runId: string; kind: string; stream: string | null; payloadJson: unknown }[]
	>;
}

/**
 * For each run in `runs` that is terminal AND has `costUsd === null`,
 * compute usage from its persisted events and overlay the result onto
 * the row. Returns rows in the same order. Non-candidate rows are
 * passed through by reference (no spread).
 *
 * Batches all candidates into a single `listUsageEvents` call so the
 * list-endpoint case is one query, not N. Empty / no-candidate inputs
 * short-circuit without touching the DB.
 */
export async function hydrateRunsUsage<T extends RunRow>(
	runs: readonly T[],
	events: UsageEventsFetcher | EventsRepo,
): Promise<T[]> {
	const candidates = runs.filter(isHydrationCandidate);
	if (candidates.length === 0) return runs.slice();
	const rows = await events.listUsageEvents(candidates.map((r) => r.id));
	const byRun = new Map<string, (typeof rows)[number][]>();
	for (const row of rows) {
		const bucket = byRun.get(row.runId);
		if (bucket === undefined) byRun.set(row.runId, [row]);
		else bucket.push(row);
	}
	return runs.map((run) => {
		if (!isHydrationCandidate(run)) return run;
		const stats = aggregateUsageFromEvents((byRun.get(run.id) ?? []).map(eventRowToUsageInput));
		if (stats === null) return run;
		return {
			...run,
			costUsd: stats.costUsd,
			tokensInput: stats.tokensInput,
			tokensOutput: stats.tokensOutput,
			tokensCacheRead: stats.tokensCacheRead,
			tokensCacheWrite: stats.tokensCacheWrite,
		};
	});
}

/**
 * Single-row convenience wrapper around `hydrateRunsUsage`. Returns the
 * input row unchanged when it's not a hydration candidate.
 */
export async function hydrateRunUsage<T extends RunRow>(
	run: T,
	events: UsageEventsFetcher | EventsRepo,
): Promise<T> {
	const [hydrated] = await hydrateRunsUsage([run], events);
	// Length-1 input ⇒ length-1 output; non-null assertion is safe.
	return hydrated as T;
}

function isHydrationCandidate(run: RunRow): boolean {
	return run.costUsd === null && TERMINAL_RUN_STATES.has(run.state);
}

/**
 * `bridgeRunStream` — the main event-bridge pump (SPEC §4.3 step 5,
 * §9 "event durability rationale"). Splits out of the legacy
 * monolithic `src/runs/stream.ts` (warren-041e / pl-9088 step 5):
 * terminal-detection lives in `./terminal-detect.ts`, the run-state
 * fallback in `./run-state-poller.ts`, cost-stats persistence in
 * `./stats.ts`, and active-stream recovery in `./recover.ts`.
 *
 * The bridge is the only writer to `events` (rows always land via
 * `bridgeRunStream` → `EventsRepo.append`); the broker is published
 * to immediately after each row commits so live tailers see fresh
 * events without waiting on a polling interval.
 *
 * See the module-level commentary in `./index.ts` for the full
 * resume / claim / terminal-detection / recovery semantics — keeping
 * docs there so the doctored stream of consciousness stays in one
 * place rather than fanning out across the split.
 */

import { NotFoundError as BurrowNotFoundError, type RunEvent } from "@os-eco/burrow-cli";
import type { BurrowClient } from "../../burrow-client/client.ts";
import { withTransportMapping } from "../../burrow-client/client.ts";
import type { EventStream, RunTerminalState } from "../../db/schema.ts";
import { EVENT_STREAMS } from "../../db/schema.ts";
import {
	accumulatePiUsage,
	extractClaudeUsage,
	newSessionStatsAccumulator,
	type SessionStatsAccumulator,
} from "../usage-aggregate.ts";
import { extractAssistantText, extractIntentPatch } from "./conversation-turn.ts";
import { defaultRunStateProbe, runStatePoller } from "./run-state-poller.ts";
import { persistInStreamUsage, persistPiStatsDelta, snapshotStats } from "./stats.ts";
import { detectRuntimeTerminal, isPiAgentEnd } from "./terminal-detect.ts";
import {
	type BridgeRunStreamInput,
	type BridgeRunStreamResult,
	type BurrowTerminalSnapshot,
	DEFAULT_RUN_STATE_DRAIN_MS,
	DEFAULT_RUN_STATE_POLL_MS,
	type RunStateProbe,
	type SessionStats,
} from "./types.ts";

/**
 * Pump events from burrow's `/runs/:id/stream` into the warren events
 * table and fan-out broker. Returns when the source iterator ends, the
 * signal aborts, or the source throws — whichever comes first.
 *
 * The function is async-iteration shaped (one pass, no resume after
 * return) — call it again from the supervisor if the bridge needs to
 * resume against a still-live burrow run.
 */
export async function bridgeRunStream(input: BridgeRunStreamInput): Promise<BridgeRunStreamResult> {
	const { runId, burrowRunId, repos, broker } = input;
	const ctrl = new AbortController();
	const onAbort = (): void => ctrl.abort();
	if (input.signal !== undefined) {
		if (input.signal.aborted) ctrl.abort();
		else input.signal.addEventListener("abort", onAbort, { once: true });
	}

	const resumeSeq = (await repos.events.maxSeqForRun(runId)) ?? 0;
	// warren-c0c9: route the stream poll through the worker that owns this
	// burrow. The source override (tests) bypasses the pool entirely.
	const sourceClient =
		input.source !== undefined
			? null
			: (await input.burrowClientPool.clientFor({ burrowId: input.burrowId })).client;
	const source = input.source ?? defaultSource(sourceClient as BurrowClient, burrowRunId);

	// warren-6596: run-state poller. Covers runtimes that don't emit a
	// recognised in-stream terminal envelope (raw-text declarative agents).
	// Skipped when neither a probe override nor a real burrow client exists
	// (tests that pass `source` but no `runStateProbe`).
	const runStateProbe: RunStateProbe | null =
		input.runStateProbe ??
		(sourceClient !== null ? defaultRunStateProbe(sourceClient as BurrowClient) : null);
	const probedTerminal: { value: BurrowTerminalSnapshot | null } = { value: null };
	const pollerTask =
		runStateProbe !== null
			? runStatePoller({
					probe: runStateProbe,
					burrowRunId,
					ctrl,
					pollIntervalMs: input.runStatePollMs ?? DEFAULT_RUN_STATE_POLL_MS,
					drainMs: input.runStateDrainMs ?? DEFAULT_RUN_STATE_DRAIN_MS,
					observed: probedTerminal,
					runId,
					...(input.logger !== undefined ? { logger: input.logger } : {}),
				})
			: null;

	let written = 0;
	let skipped = 0;
	let errored = false;
	let claimed = false;
	let terminalDetected: { outcome: RunTerminalState } | undefined;
	let burrowRunMissing = false;
	// pi cost tracking (warren-a7dc, warren-17a4). Two paths:
	//   1. In-stream extraction (default): accumulate `turn_end` usage as
	//      events flow through the bridge. Persisted on terminal.
	//   2. Out-of-band PiStatsClient (override): fetched at baseline +
	//      terminal, delta persisted. Used when the wire format doesn't
	//      carry usage (declarative stubs, custom dispatchers).
	// Both paths are best-effort; failures leave the columns null.
	let statsBaseline: Promise<SessionStats | null> | undefined;
	let statsPersisted = false;
	// warren-df71: assistant text accumulated within the current conversation
	// turn, flushed to the transcript on `agent_end` (the turn boundary).
	let conversationTurnText = "";
	const piUsage: SessionStatsAccumulator = newSessionStatsAccumulator();
	// claude-code cost tracking (warren-87f9). Single-shot: claude-code
	// emits one `result` envelope at run end carrying `total_cost_usd` +
	// `usage.{input,output,cache_read_input,cache_creation_input}_tokens`.
	// Shape-sniffed in `extractClaudeUsage`; persisted on terminal only
	// when no pi usage was observed (pi path wins for parity).
	const claudeUsage: SessionStatsAccumulator = newSessionStatsAccumulator();

	try {
		for await (const event of source(ctrl.signal)) {
			if (ctrl.signal.aborted) break;
			if (!claimed) {
				const claimedRun = await repos.runs.claimById(runId);
				if (claimedRun !== null) {
					input.logger?.info?.({ runId, burrowRunId }, "bridge transitioned run queued → running");
				}
				claimed = true;
				if (input.piStats !== undefined) {
					statsBaseline = snapshotStats(
						input.piStats,
						burrowRunId,
						ctrl.signal,
						"baseline",
						runId,
						input.logger,
					);
				}
			}
			if (event.seq <= resumeSeq) {
				skipped += 1;
				continue;
			}
			const row = await repos.events.append({
				runId,
				burrowEventSeq: event.seq,
				ts: toIsoString(event.ts),
				kind: event.kind,
				stream: normalizeStream(event.stream),
				payload: event.payload,
			});
			written += 1;
			broker.publish(runId, row);

			accumulatePiUsage(piUsage, event);
			extractClaudeUsage(claudeUsage, event);

			// warren-df71: conversation keep-alive. A mode:'conversation' run is
			// a long-lived pi-chat session — `agent_end` is a TURN boundary, not
			// a run terminal. Persist the turn's usage + assistant text, apply
			// any propose_intent patch, and KEEP the run `running` (no break, no
			// inline reap). Non-conversation runs skip this whole branch and
			// retain their exact prior lifecycle.
			if (input.mode === "conversation") {
				const assistantText = extractAssistantText(event);
				if (assistantText !== null) conversationTurnText += assistantText;
				const intentPatch = extractIntentPatch(event);
				if (intentPatch !== null) {
					await input.conversationTurn?.applyIntentPatch({ runId, patch: intentPatch });
				}
				if (isPiAgentEnd(event)) {
					await persistInStreamUsage({
						usage: piUsage,
						runtime: "pi",
						runId,
						burrowRunId,
						repos,
						logger: input.logger,
					});
					const turnText = conversationTurnText.trim();
					if (turnText.length > 0) {
						await input.conversationTurn?.persistAssistantTurn({ runId, text: turnText });
					}
					conversationTurnText = "";
					input.logger?.info?.(
						{ runId, burrowRunId, seq: event.seq },
						"conversation run: agent_end treated as turn-end; keeping run alive",
					);
					continue;
				}
			}

			if (!statsPersisted && isPiAgentEnd(event)) {
				statsPersisted = true;
				if (input.piStats !== undefined) {
					await persistPiStatsDelta({
						piStats: input.piStats,
						burrowRunId,
						runId,
						repos,
						baseline: statsBaseline,
						signal: ctrl.signal,
						logger: input.logger,
					});
				} else {
					await persistInStreamUsage({
						usage: piUsage,
						runtime: "pi",
						runId,
						burrowRunId,
						repos,
						logger: input.logger,
					});
				}
			}

			const outcome = detectRuntimeTerminal(event);
			if (outcome !== null) {
				terminalDetected = { outcome };
				input.logger?.info?.(
					{ runId, burrowRunId, outcome, seq: event.seq },
					"bridge observed runtime-terminal event; reap will finalize",
				);
				if (!statsPersisted) {
					statsPersisted = true;
					if (input.piStats !== undefined) {
						await persistPiStatsDelta({
							piStats: input.piStats,
							burrowRunId,
							runId,
							repos,
							baseline: statsBaseline,
							signal: ctrl.signal,
							logger: input.logger,
						});
					} else if (piUsage.seen) {
						// Prefer pi if observed (mixed-shape stream); claude-code
						// usage is the fallback when no pi `turn_end` ever fired.
						persistInStreamUsage({
							usage: piUsage,
							runtime: "pi",
							runId,
							burrowRunId,
							repos,
							logger: input.logger,
						});
					} else {
						persistInStreamUsage({
							usage: claudeUsage,
							runtime: "claude",
							runId,
							burrowRunId,
							repos,
							logger: input.logger,
						});
					}
				}
				break;
			}
		}
	} catch (err) {
		if (err instanceof BurrowNotFoundError) {
			// warren-b1a9: burrow no longer has this run (machine restart wiped
			// its in-memory store, deliberate cleanup, etc.). Surface as a
			// distinct terminal signal so the registry stops reconnecting and
			// reconciles the warren row to `failed` instead of spinning on
			// backoff. Don't set `errored` — errored=true triggers the reconnect
			// loop; the missing-run signal is exactly the case where reconnect
			// is hopeless.
			burrowRunMissing = true;
			input.logger?.warn?.(
				{ runId, burrowRunId, written, skipped, err: err.message },
				"run stream bridge: burrow returned 404 for burrow_run_id (ghost run)",
			);
		} else if (probedTerminal.value !== null) {
			// warren-6596: the run-state poller observed burrow terminal and
			// aborted the source. An AbortError surfacing here is intentional —
			// don't flag `errored` (which would trip the registry's reconnect
			// loop). The synthesized `terminalDetected` is set below.
			input.logger?.info?.(
				{
					runId,
					burrowRunId,
					burrowState: probedTerminal.value.state,
					err: err instanceof Error ? err.message : String(err),
				},
				"run stream bridge: stream aborted by run-state poller after terminal observation",
			);
		} else {
			errored = true;
			input.logger?.error?.(
				{
					runId,
					burrowRunId,
					written,
					skipped,
					err: err instanceof Error ? err.message : String(err),
				},
				"run stream bridge errored",
			);
		}
	} finally {
		if (input.signal !== undefined) input.signal.removeEventListener("abort", onAbort);
		ctrl.abort();
		if (pollerTask !== null) await pollerTask;
		broker.close(runId);
	}

	// warren-6596: if the in-stream terminal-detect path didn't fire but the
	// run-state poller saw burrow terminal, synthesise `terminalDetected` so
	// the registry's inline reap still runs. Outcome maps 1:1 from burrow
	// state (succeeded/failed/cancelled). Skipped when terminal was already
	// detected in-stream — the in-stream path is authoritative because it
	// carries exit_code semantics from the runtime parser.
	if (terminalDetected === undefined && !burrowRunMissing && probedTerminal.value !== null) {
		terminalDetected = { outcome: probedTerminal.value.state };
		input.logger?.info?.(
			{ runId, burrowRunId, outcome: probedTerminal.value.state },
			"bridge synthesized terminalDetected from burrow run-state probe",
		);
	}

	input.logger?.info?.(
		{ runId, burrowRunId, written, skipped, errored, burrowRunMissing },
		"run stream bridge ended",
	);
	if (burrowRunMissing) {
		return { written, skipped, errored, burrowRunMissing: true };
	}
	return terminalDetected !== undefined
		? { written, skipped, errored, terminalDetected }
		: { written, skipped, errored };
}

/**
 * Default source factory: shells through the HttpClient. Wrapping in
 * `withTransportMapping` is moot here because the iterator yields
 * after the initial fetch returns — but the initial fetch can still
 * fail with a transport error, and we want that to surface as
 * `BurrowUnreachableError` for consistency with the spawn flow.
 */
function defaultSource(
	client: BurrowClient,
	burrowRunId: string,
): (signal: AbortSignal) => AsyncIterable<RunEvent> {
	return (signal) => {
		return {
			[Symbol.asyncIterator](): AsyncIterator<RunEvent> {
				const inner = client.http.runs.stream(burrowRunId, { signal });
				return {
					next: () =>
						withTransportMapping(client.config, () => inner.next()) as Promise<
							IteratorResult<RunEvent>
						>,
					return: () => inner.return(undefined) as Promise<IteratorResult<RunEvent>>,
				};
			},
		};
	};
}

/**
 * Burrow's wire `stream` is `'stdout' | 'stderr' | 'system'`; warren's
 * column accepts the same enum but is nullable. Coerce unknown values
 * to null so a forward-compatible burrow can ship new stream tags
 * without crashing the bridge — the event still lands, just without a
 * stream tag.
 */
function normalizeStream(value: unknown): EventStream | null {
	if (typeof value !== "string") return null;
	return (EVENT_STREAMS as readonly string[]).includes(value) ? (value as EventStream) : null;
}

function toIsoString(ts: Date | string): string {
	return ts instanceof Date ? ts.toISOString() : ts;
}

